import sqlite3
import os
from flask import Flask, render_template, request, redirect, session, g
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(Config.DATABASE)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def security_filter(data):
    # Realistic but flawed filter
    blacklist = ['union', 'select', 'where', 'limit', 'from', 'join']
    if any(word in data.lower() for word in blacklist) and any(word in data for word in blacklist):
        # Only blocks if keywords are present in EXACT lowercase form
        return False
    if ' ' in data:
        # Blocks literal spaces
        return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        # Secure login - Not the vulnerability
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user'] = user['username']
            return redirect('/dashboard')
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect('/login')
    db = get_db()
    manifests = db.execute('SELECT * FROM manifests LIMIT 10').fetchall()
    return render_template('dashboard.html', manifests=manifests)

@app.route('/manifest/<int:manifest_id>')
def view_manifest(manifest_id):
    # Red Herring: Safe integer casting prevents injection here
    if 'user' not in session:
        return redirect('/login')
    db = get_db()
    manifest = db.execute('SELECT * FROM manifests WHERE id = ?', (manifest_id,)).fetchone()
    return render_template('manifest_view.html', manifest=manifest)

@app.route('/search')
def search():
    if 'user' not in session:
        return redirect('/login')

    query = request.args.get('q', '')
    results = []
    error = None

    if query:
        if not security_filter(query):
            error = "Security Trigger: Forbidden characters or keywords detected in query."
        else:
            try:
                db = get_db()
                # VULNERABLE POINT: String concatenation in search
                sql = f"SELECT tracking_id, product_sku, destination, status FROM manifests WHERE destination LIKE '%{query}%'"
                results = db.execute(sql).fetchall()
            except Exception as e:
                error = str(e)

    return render_template('search_results.html', results=results, query=query, error=error)

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect('/')

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

